import{_ as r,o as a,c as d,a2 as o}from"./chunks/framework.DZO5kRrk.js";const b=JSON.parse('{"title":"图像工具箱 — 产品规划文档","description":"","frontmatter":{},"headers":[],"relativePath":"harmony-image-toolkit.md","filePath":"harmony-image-toolkit.md"}'),e={name:"harmony-image-toolkit.md"};function n(s,t,h,i,l,g){return a(),d("div",null,[...t[0]||(t[0]=[o('<h1 id="图像工具箱-—-产品规划文档" tabindex="-1">图像工具箱 — 产品规划文档 <a class="header-anchor" href="#图像工具箱-—-产品规划文档" aria-label="Permalink to &quot;图像工具箱 — 产品规划文档&quot;">​</a></h1><p><strong>版本</strong>: v0.1 <strong>平台</strong>: HarmonyOS NEXT <strong>日期</strong>: 2026-07 <strong>开发顺序</strong>: 第 2 个（证件照工坊上线后）</p><hr><h2 id="定位" tabindex="-1">定位 <a class="header-anchor" href="#定位" aria-label="Permalink to &quot;定位&quot;">​</a></h2><p><strong>一句话</strong>：日常图片处理全能工具，替代多个分散的单功能 App。</p><p>证件照工坊解决的是&quot;证件照&quot;这个垂直场景，图像工具箱解决的是用户<strong>所有日常图片处理需求</strong>，两者互补不重叠。</p><hr><h2 id="功能模块" tabindex="-1">功能模块 <a class="header-anchor" href="#功能模块" aria-label="Permalink to &quot;功能模块&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>核心能力</th><th>技术方案</th></tr></thead><tbody><tr><td><strong>图片压缩</strong></td><td>指定目标文件大小（KB），自动迭代压缩，不让用户手动试</td><td>Image Kit 质量参数二分迭代</td></tr><tr><td><strong>格式转换</strong></td><td>JPG / PNG / WEBP 互转，支持批量</td><td>Image Kit 编解码</td></tr><tr><td><strong>图片裁剪</strong></td><td>自定义比例裁剪，内置 1:1 / 4:3 / 16:9 等常用比例快选</td><td>Image Kit + 手势交互</td></tr><tr><td><strong>水印添加</strong></td><td>文字水印/图片水印，自定义位置、大小、透明度，支持批量</td><td>Canvas 叠加绘制</td></tr><tr><td><strong>图片拼接</strong></td><td>多图垂直/横向拼接、九宫格、自定义间距</td><td>Canvas 多图布局</td></tr><tr><td><strong>去除背景</strong></td><td>批量抠图，纯色背景替换，人像智能分割</td><td>Core Vision Kit 人像分割</td></tr></tbody></table><hr><h2 id="与证件照工坊的代码复用" tabindex="-1">与证件照工坊的代码复用 <a class="header-anchor" href="#与证件照工坊的代码复用" aria-label="Permalink to &quot;与证件照工坊的代码复用&quot;">​</a></h2><p><strong>复用率：约 70%</strong></p><table tabindex="0"><thead><tr><th>复用模块</th><th>说明</th></tr></thead><tbody><tr><td>ImageProcessor 基础封装</td><td>压缩/裁剪/格式转换逻辑完全复用</td></tr><tr><td>Core Vision Kit 人像分割</td><td>证件照抠图模块直接迁移</td></tr><tr><td>FileExporter 文件导出</td><td>DocumentViewPicker 流程完全复用</td></tr><tr><td>订阅/付费体系</td><td>完全复用，接入同一套</td></tr><tr><td>通用 UI 组件库</td><td>按钮/弹窗/进度条复用</td></tr></tbody></table><p><strong>新增开发内容</strong>：Canvas 水印叠加、多图拼接布局逻辑（约 30%）</p><hr><h2 id="商业模式" tabindex="-1">商业模式 <a class="header-anchor" href="#商业模式" aria-label="Permalink to &quot;商业模式&quot;">​</a></h2><ul><li><strong>免费功能</strong>：压缩、格式转换、基础裁剪（每日限量）</li><li><strong>订阅解锁</strong>：批量处理无限制、水印功能、去背景高级模式</li><li><strong>定价参考</strong>：月付 6 元 / 年付 30 元（与证件照工坊独立订阅或合并套餐）</li></ul><hr><h2 id="里程碑" tabindex="-1">里程碑 <a class="header-anchor" href="#里程碑" aria-label="Permalink to &quot;里程碑&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阶段</th><th>内容</th><th>预计时间</th></tr></thead><tbody><tr><td>Phase 1</td><td>压缩 + 格式转换 + 裁剪（核心三件套）</td><td>3-4 天</td></tr><tr><td>Phase 2</td><td>水印 + 拼接</td><td>3-4 天</td></tr><tr><td>Phase 3</td><td>去背景批量处理</td><td>2-3 天</td></tr><tr><td><strong>合计</strong></td><td><strong>MVP 上线</strong></td><td><strong>约 10 天</strong></td></tr></tbody></table><hr><h2 id="差异化关键点" tabindex="-1">差异化关键点 <a class="header-anchor" href="#差异化关键点" aria-label="Permalink to &quot;差异化关键点&quot;">​</a></h2><blockquote><p>市面上&quot;图片压缩工具&quot;都是让用户自己拉压缩率滑块，反复试。 本产品直接输入目标大小&quot;我要压到 500KB 以内&quot;，自动搞定。 这一个细节就能把用户从竞品拉过来。</p></blockquote>',23)])])}const m=r(e,[["render",n]]);export{b as __pageData,m as default};
